public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    protected override void OnLoad(EventArgs e)
    {
        base.OnLoad(e);

        _statusStrip = new StatusStrip();
        // .NET 9 changed the default StatusStrip render mode;
        // set it explicitly to preserve the .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }
}

public class SafeDropDownEditor : UITypeEditor
{
    public override object EditValue(
        System.ComponentModel.ITypeDescriptorContext context,
        IServiceProvider provider,
        object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        var control = BuildEditControl(value);

        // .NET 9 throws ArgumentNullException when null is passed to DropDownControl.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = control.Tag;
        }

        return value;
    }

    private static Control BuildEditControl(object value)
    {
        var listBox = new ListBox();
        listBox.Tag = value;
        return listBox;
    }
}

